#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int n,m,op[N],val[N],g[30][2],ans;
char s[5];

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%s",s+1);
        scanf("%d",&val[i]);
        if(s[1]=='A')
            op[i]=0;
        else if(s[1]=='O')
            op[i]=1;
        else
            op[i]=2;
    }
    for(int i=0;i<30;i++){
        g[i][0]=0,g[i][1]=1;
        for(int j=1;j<=n;j++){
            int vis=((val[j]>>i)&1);
            if(op[j]==0)
                g[i][0]&=vis,g[i][1]&=vis;
            else if(op[j]==1)
                g[i][0]|=vis,g[i][1]|=vis;
            else
                g[i][0]^=vis,g[i][1]^=vis;
        }
    }
    bool flag=0;
    for(int i=29;i>=0;i--){
        if(g[i][0])
            ans+=(1<<i),flag|=((m>>i)&1);
        else if(g[i][1] && (flag || ((m>>i)&1)))
            ans+=(1<<i);
        else if(!(g[i][0]+g[i][1]))
            flag|=((m>>i)&1);
    }
    printf("%d",ans);
    return 0;
}
